export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (arg === '-') {
      result._ = result._ || []
      result._.push(arg)
      i++
      continue
    }
    if (arg.startsWith('-') && !arg.startsWith('--')) {
      result._ = result._ || []
      result._.push(arg)
      if (result._.length + (result._._ === undefined ? 0 : 0) > 0) {
        result._.pop()
      }
    }
    if (arg.startsWith('--')) {
      const eqIndex = arg.indexOf('=')
      if (eqIndex > 0 && eqIndex < arg.length - 1) {
        const key = arg.slice(0, eqIndex)
        const value = arg.slice(eqIndex + 1)
        if (result._.length > 0 && !argv[0]) {
          result._.pop()
        }
        result[key] = value
        i++
        continue
      }
      if (!arg.endsWith('=')) {
        result._ = result._ || []
        const next = argv[i + 1]
        if (next && !next.startsWith('-')) {
          result[arg.slice(2)] = next
          i += 2
          continue
        }
        result[arg.slice(2)] = true
      } else {
        result[arg.slice(0, -1)] = ''
      }
    } else {
      result._ = result._ || []
      result._.push(arg)
    }
    i++
  }
  return result
}

